(()=>{document.addEventListener("DOMContentLoaded",()=>{document.querySelectorAll(".textarea-field[maxlength]").forEach(t=>{let e=t.closest(".textarea-group"),n=e&&e.querySelector(".textarea-count");if(!n)return;let o=()=>{n.textContent=t.value.length+" / "+t.maxLength};t.addEventListener("input",o),o()})});})();
